declare const __IIFE__: (document: Document, window: Window, cleanWindow: any) => (...args: any[]) => Promise<any> | any

function sandbox(...args: any[]) {
  const ctor = __IIFE__
  let isCSP = true

  try {
    let iframeEl = (window as any).__applitools_sandbox

    if (!iframeEl) {
      iframeEl = document.createElement('iframe')
      iframeEl.setAttribute('data-applitools-sandbox', '')
      iframeEl.setAttribute('data-applitools-skip', '')
      document.head.appendChild(iframeEl)
      ;(window as any).__applitools_sandbox = iframeEl
    }

    // Use Math.random() instead of window.crypto.getRandomValues for IE10 compatibility.
    const id = Math.floor(Math.random() * 0x100000000)
    const script = iframeEl.contentDocument.createElement('script')
    script.textContent = "window['ctor-" + id + "'] = " + ctor.toString() + ';'

    iframeEl.contentDocument.head.appendChild(script)
    const func = (iframeEl.contentWindow as any)['ctor-' + id]
    delete (iframeEl.contentWindow as any)['ctor-' + id]

    if (typeof func !== 'function') throw new Error('Sandbox failed to extract function')

    isCSP = false

    const iw = iframeEl.contentWindow as any
    // Cache iframe's native JSON.stringify on the iframe's namespace so inner functions
    // can use it via window.__EYES__APPLITOOLS__._stringify regardless of main-page patches.
    const iwEyesNs: any = (iw.__EYES__APPLITOOLS__ = iw.__EYES__APPLITOOLS__ || {})
    if (!iwEyesNs._stringify) {
      iwEyesNs._stringify = iw.JSON.stringify.bind(iw.JSON)
    }
    // Also cache on the main window for any fallback paths that run outside the sandbox.
    const eyesNs: any = ((window as any).__EYES__APPLITOOLS__ = (window as any).__EYES__APPLITOOLS__ || {})
    if (!eyesNs._stringify || eyesNs._stringify === JSON.stringify) {
      eyesNs._stringify = iw.JSON.stringify.bind(iw.JSON)
    }

    function toNative(v: any): any {
      if (iw.Array.isArray(v)) {
        const r = new iw.Array(v.length)
        for (let i = 0; i < v.length; i++) r[i] = toNative(v[i])
        return r
      } else if (v && typeof v === 'object' && Object.getPrototypeOf(v) === Object.prototype) {
        const r = new iw.Object()
        for (const k in v) {
          if (Object.prototype.hasOwnProperty.call(v, k)) r[k] = toNative(v[k])
        }
        return r
      }
      return v
    }

    const nativeArgs = new iw.Array(args.length)
    for (let i = 0; i < args.length; i++) nativeArgs[i] = toNative(args[i])

    // window = main page's window (page inspection: frameElement, navigator, state storage)
    // iw (cleanWindow) = sandbox iframe's window (clean DOM prototypes: Node.prototype, HTMLElement, etc.)
    // In fallback (sandbox failed), cleanWindow === window — no clean context available.
    return func(document, window, iw)(...nativeArgs)
  } catch (sandboxErr) {
    try {
      return ctor(document, window, window)(...args)
    } catch (mainErr) {
      throw isCSP ? mainErr : sandboxErr
    }
  }
}

export default sandbox
